const body = $input.first().json.body || $input.first().json;
const data = body.data || body;

// Apenas mensagens recebidas
if (body.event && body.event !== 'messages.upsert') return [];

const key = data.key || (data.message && data.message.key) || {};
const fromMe = key.fromMe || data.fromMe || false;
const remoteJid = key.remoteJid || data.remoteJid || '';
const telefone = remoteJid.replace('@s.whatsapp.net','').replace('@g.us','');
const pushName = data.pushName || '';
const messageId = key.id || '';

const msg = data.message || {};
let mensagem = msg.conversation
  || msg.extendedTextMessage?.text
  || msg.imageMessage?.caption
  || data.body || '';
let tipo = 'texto';

// Comando de reativação do bot
if (fromMe) {
  const lower = (mensagem || '').trim().toLowerCase();
  if (lower === '/bot' || lower === '/reativar') {
    return [{ json: { telefone, mensagem: '__REATIVAR_BOT__', tipo: 'comando', remoteJid, pushName, messageId, fromMe: true, comandoBot: true } }];
  }
  return [];
}

// Detectar áudio (audioMessage / pttMessage)
const audioMsg = msg.audioMessage || msg.pttMessage || null;
if (audioMsg) {
  tipo = 'audio';
  try {
    // 1) Baixar base64 da Evolution API
    const evoResp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://evolution.nateksoft.com/chat/getBase64FromMediaMessage/Clinica',
      headers: { apikey: 'nateksoft', 'Content-Type': 'application/json' },
      body: { message: { key } },
      json: true,
    });
    const b64 = evoResp.base64 || evoResp.data?.base64 || '';
    if (!b64) throw new Error('Evolution não retornou base64');

    // 2) Enviar para Groq Whisper (multipart/form-data)
    const buf = Buffer.from(b64, 'base64');
    const FormData = require('form-data');
    const fd = new FormData();
    fd.append('file', buf, { filename: 'audio.ogg', contentType: 'audio/ogg' });
    fd.append('model', 'whisper-large-v3');
    fd.append('language', 'pt');
    fd.append('response_format', 'json');

    const groqResp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.groq.com/openai/v1/audio/transcriptions',
      headers: { Authorization: 'Bearer COLE_SUA_GROQ_KEY_AQUI', ...fd.getHeaders() },
      body: fd,
    });
    const parsed = typeof groqResp === 'string' ? JSON.parse(groqResp) : groqResp;
    mensagem = '🎙️ (áudio): ' + (parsed.text || '').trim();
  } catch (e) {
    mensagem = '🎙️ (áudio não transcrito): ' + (e.message || 'erro');
  }
}

return [{ json: { telefone, mensagem, tipo, remoteJid, pushName, messageId, fromMe: false, comandoBot: false } }];

// v12.1 — bot fica MUDO apenas quando status_sessao === 'humano'.
// Qualquer outro estado ('ia','menu','agendamento',null,etc) o bot continua ativo.
const dados = $input.first().json;
const dadosMensagem = $('Extrair Dados da Mensagem').first().json;

let pacientes = [];
if (Array.isArray(dados)) {
  pacientes = dados;
} else if (Array.isArray(dados.body)) {
  pacientes = dados.body;
} else if (typeof dados.body === 'string') {
  try { pacientes = JSON.parse(dados.body); } catch (_) { pacientes = []; }
} else if (dados && typeof dados === 'object' && dados.telefone) {
  pacientes = [dados];
}

const paciente = pacientes.length > 0 ? pacientes[0] : null;
const status = (paciente && paciente.status_sessao) ? String(paciente.status_sessao) : 'ia';

// Comando explícito de reativação sobrepõe humano
const comandoBot = !!dadosMensagem.comandoBot;
const statusFinal = comandoBot ? 'ia' : status;

// Bot só fica MUDO em 'humano'. Em qualquer outro estado, continua ativo.
const botAtivo = comandoBot ? true : (statusFinal !== 'humano');

return [{
  json: {
    telefone: dadosMensagem.telefone,
    mensagem: dadosMensagem.mensagem,
    remoteJid: dadosMensagem.remoteJid,
    pushName: dadosMensagem.pushName,
    tipo: dadosMensagem.tipo || 'texto',
    messageId: dadosMensagem.messageId || '',
    comandoBot,
    nome: (paciente && paciente.nome) || dadosMensagem.pushName || '',
    paciente_existe: !!paciente,
    paciente_id: paciente ? paciente.id : null,
    status_sessao: statusFinal,
    bot_ativo: botAtivo
  }
}];

